import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button, Grid, Typography, Box } from '@mui/material';

function Dashboard() {
  const [role, setRole] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    const storedRole = localStorage.getItem('role');
    if (!storedRole) {
      navigate('/login'); // Redirect to login if no role is found
    } else {
      setRole(storedRole);
    }
  }, [navigate]);

  return (
    <Box
      sx={{
        padding: 3,
        maxWidth: 600,
        margin: '50px auto',
        backgroundColor: '#f9f9f9',
        borderRadius: 2,
        boxShadow: '0px 4px 10px rgba(0, 0, 0, 0.1)',
        textAlign: 'center',
      }}
    >
      <Typography
        variant="h4"
        sx={{ fontSize: '24px', fontWeight: 'bold', color: '#333', marginBottom: 2 }}
      >
        Dashboard
      </Typography>

      {role === 'Manager' && (
        <Box
          sx={{
            backgroundColor: '#fff',
            padding: 2,
            borderRadius: 1,
            boxShadow: '0px 2px 5px rgba(0, 0, 0, 0.1)',
            marginBottom: 3,
          }}
        >
          <Typography
            variant="h5"
            sx={{ fontSize: '20px', fontWeight: '600', color: '#555', marginBottom: 2 }}
          >
            Manager Dashboard
          </Typography>
          <Grid container spacing={2} justifyContent="center">
            <Grid item xs={12} sm={4}>
              <Button
                variant="contained"
                fullWidth
                href="/employee"
                sx={{ backgroundColor: '#1976d2', color: 'white' }}
              >
                Employee
              </Button>
            </Grid>
            <Grid item xs={12} sm={4}>
              <Button
                variant="contained"
                fullWidth
                href="/company"
                sx={{ backgroundColor: '#1976d2', color: 'white' }}
              >
                Company
              </Button>
            </Grid>
            <Grid item xs={12} sm={4}>
              <Button
                variant="contained"
                fullWidth
                href="/record"
                sx={{ backgroundColor: '#1976d2', color: 'white' }}
              >
                Records
              </Button>
            </Grid>
          </Grid>
        </Box>
      )}

      {role === 'Employee' && (
        <Box
          sx={{
            backgroundColor: '#fff',
            padding: 2,
            borderRadius: 1,
            boxShadow: '0px 2px 5px rgba(0, 0, 0, 0.1)',
          }}
        >
          <Typography
            variant="h5"
            sx={{ fontSize: '20px', fontWeight: '600', color: '#555', marginBottom: 2 }}
          >
            Employee Dashboard
          </Typography>
          <Grid container spacing={2} justifyContent="center">
            <Grid item xs={12} sm={4}>
              <Button
                variant="contained"
                fullWidth
                href="/work-entry"
                sx={{ backgroundColor: '#1976d2', color: 'white' }}
              >
                Work Entry
              </Button>
            </Grid>
            <Grid item xs={12} sm={4}>
              <Button
                variant="contained"
                fullWidth
                href="/work-details"
                sx={{ backgroundColor: '#1976d2', color: 'white' }}
              >
                Work Details
              </Button>
            </Grid>
            <Grid item xs={12} sm={4}>
              <Button
                variant="contained"
                fullWidth
                href="/create-company"
                sx={{ backgroundColor: '#1976d2', color: 'white' }}
              >
                Create Company
              </Button>
            </Grid>
          </Grid>
        </Box>
      )}
    </Box>
  );
}

export default Dashboard;
